// === Javaプログラムの実行手順 ===

// ステップ1: ソースファイルを作成する
//   Hello.java というファイル名で保存

// ステップ2: コンパイル（ソースコードを変換）
//   javac Hello.java
//   → Hello.class（バイトコード）が生成される

// ステップ3: 実行（プログラムを動かす）
//   java Hello
//   → 画面にメッセージが表示される

// Javaプログラムの基本構造
// すべてのコードは「クラス」の中に書く
public class Hello {
    // mainメソッド: プログラムの開始地点
    public static void main(String[] args) {
        // コンソールにメッセージを表示する
        System.out.println("Hello, World!");
    }
}

